import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [categoriaActual, setCategoriaActual] = useState({
    id: null,
    nombre: "",
    descripcion: "",
  });

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoria) => {
    setCategoriaSeleccionada(categoria);
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria.id}`
      );
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "", descripcion: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (categoria) => {
    setCategoriaActual(categoria);
    setModoEdicion(true);
    setShowModal(true);
  };

  const handleChange = (e) => {
    setCategoriaActual({ ...categoriaActual, [e.target.name]: e.target.value });
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.id}`,
          categoriaActual
        );
      } else {
        await axios.post("http://localhost:5000/api/categorias", categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  return (
    <div className="container mt-5">
      {/* HEADER */}
      <div className="d-flex justify-content-between align-items-center mb-5">
        <h2 className="fw-bold text-center mb-0">Categorías</h2>
        {!categoriaSeleccionada && (
          <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
            ➕ Agregar Categoría
          </button>
        )}
      </div>

      {/* VISTA DE PRODUCTOS DE UNA CATEGORÍA */}
      {categoriaSeleccionada ? (
        <div>
          <h3 className="text-center mb-4">
            Productos en “{categoriaSeleccionada.nombre}”
          </h3>

          {productos.length > 0 ? (
            <div className="table-responsive">
              <table className="table table-bordered text-center align-middle">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Precio</th>
                    <th>Stock</th>
                  </tr>
                </thead>
                <tbody>
                  {productos.map((p) => (
                    <tr key={p.ProductoID}>
                      <td>{p.ProductoID}</td>
                      <td>{p.Nombre}</td>
                      <td>${p.Precio}</td>
                      <td>{p.Stock}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p className="text-center text-muted">
              No hay productos en esta categoría.
            </p>
          )}

          <div className="text-center mt-4">
            <button
              className="btn btn-secondary btn-lg"
              onClick={() => setCategoriaSeleccionada(null)}
            >
              🔙 Volver a Categorías
            </button>
          </div>
        </div>
      ) : (
        <>
          {/* LISTA DE CATEGORÍAS */}
          <div className="row justify-content-center">
            {categorias.map((cat) => (
              <div key={cat.id} className="col-10 col-md-4 col-lg-3 mb-4">
                <div
                  className="card shadow-lg border-0 text-center p-4 position-relative"
                  style={{
                    cursor: "pointer",
                    transition: "0.3s",
                    minHeight: "150px",
                  }}
                >
                  <h4
                    className="fw-bold mb-2"
                    onClick={() => mostrarProductosPorCategoria(cat)}
                  >
                    {cat.nombre}
                  </h4>
                  <p
                    className="small text-muted mb-3"
                    onClick={() => mostrarProductosPorCategoria(cat)}
                  >
                    {cat.descripcion || "Sin descripción"}
                  </p>

                  <div className="d-flex justify-content-center gap-2">
                    <button
                      className="btn btn-warning btn-sm"
                      onClick={() => abrirModalEditar(cat)}
                    >
                      ✏️ Editar
                    </button>
                    <button
                      className="btn btn-danger btn-sm"
                      onClick={() => eliminarCategoria(cat.id)}
                    >
                      🗑️ Eliminar
                    </button>
                  </div>
                </div>
              </div>
            ))}

            {categorias.length === 0 && (
              <p className="text-center text-muted">No hay categorías.</p>
            )}
          </div>
        </>
      )}

      {/* MODAL AGREGAR / EDITAR */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Editar Categoría" : "Agregar Nueva Categoría"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>

              <div className="modal-body">
                <form onSubmit={guardarCategoria}>
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      name="nombre"
                      value={categoriaActual.nombre}
                      onChange={handleChange}
                      className="form-control"
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Descripción</label>
                    <textarea
                      name="descripcion"
                      value={categoriaActual.descripcion}
                      onChange={handleChange}
                      className="form-control"
                      rows="3"
                    ></textarea>
                  </div>
                  <div className="text-end">
                    <button
                      type="button"
                      className="btn btn-secondary me-2"
                      onClick={() => setShowModal(false)}
                    >
                      Cancelar
                    </button>
                    <button type="submit" className="btn btn-primary">
                      {modoEdicion ? "Guardar Cambios" : "Guardar Categoría"}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
